fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val prefix = LongArray(n + 1)
    for (i in 0 until n) {
        prefix[i + 1] = prefix[i] + nums[i]
    }

    val leftIncStart = IntArray(n).apply {
        this[0] = 0
        for (i in 1 until n) {
            if (nums[i] > nums[i - 1]) {
                this[i] = this[i - 1]
            } else {
                this[i] = i
            }
        }
    }

    val incR = IntArray(n).apply {
        this[n - 1] = n - 1
        for (i in n - 2 downTo 0) {
            if (nums[i] < nums[i + 1]) {
                this[i] = this[i + 1]
            } else {
                this[i] = i
            }
        }
    }

    val decL = IntArray(n).apply {
        this[0] = 0
        for (i in 1 until n) {
            if (nums[i] < nums[i - 1]) {
                this[i] = this[i - 1]
            } else {
                this[i] = i
            }
        }
    }

    val totalSize = n + 1
    val logn = 32 - Integer.numberOfLeadingZeros(totalSize)
    val stMin = Array(logn) { LongArray(totalSize) }
    val stMax = Array(logn) { LongArray(totalSize) }

    for (i in 0 until totalSize) {
        stMin[0][i] = prefix[i]
        stMax[0][i] = prefix[i]
    }

    for (k in 1 until logn) {
        val shift = 1 shl (k - 1)
        for (i in 0 until totalSize) {
            stMin[k][i] = stMin[k - 1][i]
            stMax[k][i] = stMax[k - 1][i]
            if (i + shift < totalSize) {
                stMin[k][i] = minOf(stMin[k][i], stMin[k - 1][i + shift])
                stMax[k][i] = maxOf(stMax[k][i], stMax[k - 1][i + shift])
            }
        }
    }

    fun queryMin(l: Int, r: Int): Long {
        if (l > r) return Long.MAX_VALUE
        val len = r - l + 1
        val k = 31 - Integer.numberOfLeadingZeros(len)
        return minOf(stMin[k][l], stMin[k][r - (1 shl k) + 1])
    }

    fun queryMax(l: Int, r: Int): Long {
        if (l > r) return Long.MIN_VALUE
        val len = r - l + 1
        val k = 31 - Integer.numberOfLeadingZeros(len)
        return maxOf(stMax[k][l], stMax[k][r - (1 shl k) + 1])
    }

    var ans = Long.MIN_VALUE
    for (q in 0 until n) {
        val p = decL[q]
        if (p == q) continue
        if (leftIncStart[p] <= p - 1) {
            if (incR[q] >= q + 1) {
                val minVal = queryMin(leftIncStart[p], p - 1)
                val maxVal = queryMax(q + 1, incR[q] + 1)
                val candidate = maxVal - minVal
                if (candidate > ans) {
                    ans = candidate
                }
            }
        }
    }
    return ans
}
