    class SegTree(private val size: Int, private val arr: LongArray) {
        private val tree: LongArray = LongArray(4 * size) { Long.MIN_VALUE }

        private fun buildTree(idx: Int, left: Int, right: Int) {
            if (left == right) {
                tree[idx] = arr[left]
                return
