class SegTreeMin(private val size: Int, val identity: Long, raw: LongArray) {
    private var N = 1
    private val a: LongArray

    init {
        while (N < size) {
            N *= 2
        }
        a = LongArray(2 * N) { identity }
        for (i in 0 until size) {
            a[N + i] = raw[i]
        }
        for (i in N - 1 downTo 1) {
            a[i] = minOf(a[2 * i], a[2 * i + 1])
        }
    }

    fun query(l: Int, r: Int): Long {
        if (l > r || l < 0 || r >= size) return identity
        var l0 = l
        var r0 = r
        var res = identity
        l0 += N
        r0 += N
        while (l0 <= r0) {
            if ((l0 and 1) == 1) {
                res = minOf(res, a[l0])
                l0 += 1
            }
            if ((r0 and 1) == 0) {
                res = minOf(res, a[r0])
                r0 -= 1
            }
            l0 = l0 shr 1
            r0 = r0 shr 1
        }
        return res
    }
}

